files.content:
input {
    keyboard {
        xkb {
            layout "us"
        }
    }
}

spawn-at-startup "waybar"
spawn-at-startup "swaybg" "-c" "#1e1e2e"
spawn-at-startup "mako"

prefer-no-csd

layout {
    gaps 16
    focus-ring {
        width 3
        active-color "#cba6f7"
        inactive-color "#45475a"
    }
}

binds {
    Mod+Return { spawn "foot"; }
    Mod+D { spawn "fuzzel"; }
    Mod+Q { close-window; }
    Mod+Left { focus-column-left; }
    Mod+Right { focus-column-right; }
    Mod+1 { focus-workspace 1; }
    Mod+2 { focus-workspace 2; }
    Mod+Shift+E { quit; }
}

* { font-family: "JetBrainsMono Nerd Font"; font-size: 13px; }
window#waybar { background: #1e1e2e; color: #cdd6f4; }
#workspaces button.active { color: #cba6f7; }
#clock { color: #cba6f7; padding: 0 14px; font-weight: bold; }
#cpu { color: #89b4fa; padding: 0 10px; }
#memory { color: #a6e3a1; padding: 0 10px; }
#network { color: #94e2d5; padding: 0 10px; }
